using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
stack<int> st;
int QuickPow(int a, int b)
{
	int ans = 1;
	while (b)
	{
		if (b & 1)ans *= a;
		a *= a;
		b >>= 1;
	}
	return ans;
}
int main(void)
{
	int n;
	cin >> n;
	if (n & 1)
	{
		cout << "-1";
		return false;
	}
	for (int i = 0; i < (log2(n) + 1); i++)
	{
		if (((n >> i) & 1))st.push(QuickPow(2, i));
	}
	while (st.size())
	{
		cout << st.top() << ' ';
		st.pop();
	}
	return false;
}
